saved = []

class MyModel:
    def __init__(self, **fields):
        self.fields = fields
        self.in_db = False
    @classmethod
    def create(cls, **fields):
        obj = cls(**fields)
        obj.in_db = True
        saved.append(obj)
        return obj

m = MyModel.create(name='x')
print(m.in_db, len(saved))
